#!/usr/bin/env python3
"""Generate premium vertical demo sites from data/stratos_demo_site_system.json."""
from pathlib import Path
import html, json
ROOT=Path(__file__).resolve().parents[1]
data=json.loads((ROOT/'data'/'stratos_demo_site_system.json').read_text())
out=ROOT/'vertical-demos'; out.mkdir(exist_ok=True)
CSS="""
:root{color-scheme:dark;--bg:#030605;--ink:#f8faf6;--muted:#b8c6bc;--line:rgba(255,255,255,.12);--accent:ACCENT}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 10% 0%,color-mix(in srgb,var(--accent) 24%,transparent),transparent 36%),linear-gradient(135deg,#030605,#07100b 55%,#05070a);color:var(--ink);font:15px/1.5 Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;overflow-x:hidden}a{color:inherit;text-decoration:none}.nav{position:sticky;top:0;z-index:8;display:flex;justify-content:space-between;align-items:center;padding:18px clamp(18px,4vw,54px);backdrop-filter:blur(20px);background:rgba(3,6,5,.72);border-bottom:1px solid var(--line)}.mark{width:38px;height:38px;border-radius:13px;background:linear-gradient(135deg,var(--accent),#ffffff);display:grid;place-items:center;color:#030605;font-weight:950}.brand{display:flex;align-items:center;gap:10px;font-weight:900}.nav span{color:var(--muted);font-size:12px}.hero{position:relative;min-height:82vh;display:grid;grid-template-columns:minmax(0,1fr) minmax(360px,.82fr);gap:34px;align-items:center;padding:clamp(28px,6vw,72px);overflow:hidden}.hero:before{content:"";position:absolute;inset:0;background:linear-gradient(90deg,#030605 0%,rgba(3,6,5,.88) 35%,rgba(3,6,5,.20) 76%);z-index:1}.hero:after{content:"";position:absolute;inset:0;background:linear-gradient(115deg,transparent,rgba(255,255,255,.13),transparent);transform:translateX(-90%);animation:sheen 6s ease-in-out infinite;z-index:3;pointer-events:none}.hero-img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;opacity:.62;filter:saturate(.96) contrast(1.05)}.hero-content,.hero-panel{position:relative;z-index:4}.eyebrow{color:var(--accent);font-size:12px;font-weight:950;text-transform:uppercase;letter-spacing:.13em}.hero h1{font-size:clamp(46px,7.2vw,94px);line-height:.94;letter-spacing:-.035em;word-spacing:.05em;max-width:920px;margin:10px 0 18px;text-wrap:balance}.hero p{font-size:18px;color:#d9e2dc;max-width:760px}.actions{display:flex;flex-wrap:wrap;gap:10px;margin-top:24px}.btn{border:1px solid transparent;border-radius:999px;padding:13px 17px;font-weight:950;background:linear-gradient(135deg,var(--accent),#f8faf6);color:#030605}.btn.ghost{background:rgba(255,255,255,.06);color:var(--ink);border-color:var(--line)}.hero-panel{padding:22px;border:1px solid var(--line);border-radius:28px;background:rgba(3,6,5,.58);box-shadow:0 30px 90px rgba(0,0,0,.36),inset 0 1px rgba(255,255,255,.08)}.hero-panel b{display:block;font-size:26px;line-height:1.1;margin:8px 0}.hero-panel small{color:var(--muted)}main{padding:0 clamp(18px,4vw,54px) 64px}.grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:16px}.card{position:relative;overflow:hidden;padding:22px;border:1px solid var(--line);border-radius:26px;background:linear-gradient(180deg,rgba(255,255,255,.07),rgba(255,255,255,.025));box-shadow:0 18px 60px rgba(0,0,0,.2);animation:rise .55s cubic-bezier(.16,1,.3,1) both}.card:nth-child(2){animation-delay:.08s}.card:nth-child(3){animation-delay:.16s}.card h2{font-size:28px;line-height:1.08;letter-spacing:-.035em;margin:8px 0 12px}.card p,.card li{color:var(--muted)}.pills{display:flex;flex-wrap:wrap;gap:8px}.pill{border:1px solid color-mix(in srgb,var(--accent) 36%,transparent);background:color-mix(in srgb,var(--accent) 11%,transparent);border-radius:999px;padding:8px 10px;color:#f8faf6;font-weight:800;font-size:12px}.flow{display:grid;grid-template-columns:repeat(6,minmax(0,1fr));gap:10px;margin-top:18px}.node{min-height:110px;padding:14px;border:1px solid var(--line);border-radius:20px;background:rgba(255,255,255,.04)}.node span{color:var(--accent);font-weight:950}.node b{display:block;margin-top:8px}.proof{margin-top:18px;padding:18px;border:1px solid color-mix(in srgb,var(--accent) 32%,transparent);border-radius:22px;background:color-mix(in srgb,var(--accent) 9%,transparent);color:#eafff3}.sticky{position:fixed;right:18px;bottom:18px;z-index:9;display:flex;gap:8px}.sticky a{box-shadow:0 16px 50px rgba(0,0,0,.28)}@keyframes sheen{0%,45%{transform:translateX(-90%)}65%,100%{transform:translateX(90%)}}@keyframes rise{from{opacity:0;transform:translateY(16px);filter:blur(8px)}to{opacity:1;transform:none;filter:none}}@media(max-width:980px){.hero{grid-template-columns:1fr;min-height:auto}.hero:before{background:linear-gradient(180deg,#030605,rgba(3,6,5,.62))}.grid,.flow{grid-template-columns:1fr}.sticky{position:static;padding:0 18px 22px}}@media(prefers-reduced-motion:reduce){*,*:before,*:after{animation:none!important;transition:none!important}}
"""
TEMPLATE="""<!doctype html><html lang=\"en\"><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1\"><title>{brand} — Stratos {vertical} Demo</title><style>{css}</style></head><body><nav class=\"nav\"><div class=\"brand\"><div class=\"mark\">S</div><div>Stratos AI <span>{vertical} demo</span></div></div><a class=\"btn ghost\" href=\"../index.html#demos\">Command Center</a></nav><section class=\"hero\"><img class=\"hero-img\" src=\".{heroImage}\" alt=\"{vertical} hero generated by GPT Image 2 OAuth\"><div class=\"hero-content\"><p class=\"eyebrow\">Premium vertical demo · generated hero imagery</p><h1>{headline}</h1><p>{subhead}</p><div class=\"actions\"><a class=\"btn\" href=\"../index.html#pricing\">Scope this build</a><a class=\"btn ghost\" href=\"../index.html#crm\">Move to CRM</a></div></div><aside class=\"hero-panel\"><span class=\"eyebrow\">Demo brand</span><b>{brand}</b><small>{offer} · {price}</small><div class=\"proof\">{proof}</div></aside></section><main><section class=\"grid\"><article class=\"card\"><p class=\"eyebrow\">Offer</p><h2>{offer}</h2><p>Built to turn first-click interest into captured intent, routed follow-up, and clearer sales conversations.</p></article><article class=\"card\"><p class=\"eyebrow\">Modules</p><h2>What the page sells</h2><div class=\"pills\">{modules}</div></article><article class=\"card\"><p class=\"eyebrow\">Commercial anchor</p><h2>{price}</h2><p>Use the pricing calculator in the Command Center to adjust setup, monthly fee, automation complexity, and ROI framing.</p></article></section><section class=\"card\" style=\"margin-top:18px\"><p class=\"eyebrow\">Automation path</p><h2>From prospect intent to booked next step</h2><div class=\"flow\">{workflow}</div></section></main><div class=\"sticky\"><a class=\"btn ghost\" href=\"../index.html#proof\">Proof Vault</a><a class=\"btn\" href=\"../index.html#launch\">School-safe launch</a></div></body></html>"""
for v in data['verticals']:
    css=CSS.replace('ACCENT', v['accent'])
    modules=''.join(f"<span class='pill'>{html.escape(x)}</span>" for x in v['modules'])
    workflow=''.join(f"<div class='node'><span>{i+1:02d}</span><b>{html.escape(x)}</b></div>" for i,x in enumerate(v['workflow']))
    page=TEMPLATE.format(css=css, modules=modules, workflow=workflow, **{k:html.escape(str(val)) for k,val in v.items() if not isinstance(val,list)})
    (out/f"{v['slug']}.html").write_text(page)
print(f"Generated {len(data['verticals'])} vertical demo sites in {out}")
